INSERT INTO "Question" ("id", "testId", "questionText", "questionType", "points", "orderNumber", "textExpectedAnswer", "textManualGrading", "explanation", "topic") VALUES
('cmpouzutx0125lkse48ghfe9k', 'cmp45qury00ldn52b0gctl61z', 'Много `failed password` для одной учётной записи за короткое время. Что предположить?', 'SITUATION', '10', '6', NULL, 'f', 'Массовые неудачи — повод для защитных мер по регламенту, не для самолечения удалением логов.', NULL),
('cmpouzuu0012blksetsxe691d', 'cmp45qury00ldn52b0gctl61z', 'Пользователь требует «выключить логи, они шпионят». Корректная линия?', 'SITUATION', '10', '7', NULL, 'f', 'Объяснение назначения и политики лучше, чем необдуманное отключение мониторинга.', NULL),
('cmpouzuu2012hlksekmxmv1bx', 'cmp45qury00ldn52b0gctl61z', 'В учебном кейсе видите подозрительную команду в журнале, которая могла изменить данные. Что не делать?', 'SITUATION', '10', '8', NULL, 'f', 'Следы важны для разборов. Удаление логов мешает восстановлению картины.', NULL),
('cmpouzuu3012nlksecy63jhyk', 'cmp45qury00ldn52b0gctl61z', 'Какие действия ближе к аккуратной реакции на возможный инцидент (внимание к деталям)?', 'MULTIPLE_CHOICE', '10', '9', NULL, 'f', 'Фиксация, сдерживание, эскалация — базовая тройка. Публикация сырых логов — почти всегда плохо.', NULL),
('cmpouzuu5012tlksezvo4vcee', 'cmp45qury00ldn52b0gctl61z', 'Внимание: чем дольше хранятся логи, тем всегда лучше без учёта приватности и закона.', 'TRUE_FALSE', '10', '10', NULL, 'f', 'Баланс: сроки хранения, минимизация ПДн, доступ по ролям.', NULL);